/**
 * ============================================================================
 * NORMALISATION & VALIDATION DES DONNÉES TELEGRAM
 * ============================================================================
 * 
 * Ce module effectue :
 * 1. Validation des champs obligatoires (update_id, from.id)
 * 2. Extraction et normalisation de toutes les données Telegram
 * 3. Conversion des timestamps UNIX vers DATETIME SQL Server
 * 4. Nettoyage des chaînes pour prévenir les injections SQL
 * 5. Génération d'un objet JSON prêt pour insertion SQL
 * 
 * Table cible : [X3BI].[dbo].[telegram_messages]
 * 
 * @author Workflow Production
 * @version 2.0.0
 * ============================================================================
 */

// ============================================================================
// EXTRACTION DES DONNÉES BRUTES
// ============================================================================

const update = $input.item.json;
const message = update.message || {};
const from = message.from || {};
const chat = message.chat || {};
const entities = message.entities || [];

// ============================================================================
// VALIDATION DES CHAMPS OBLIGATOIRES
// ============================================================================

/**
 * Vérifie la présence des champs requis
 * Lance une exception si les données sont invalides
 */
function validateRequiredFields(updateId, userId) {
  const errors = [];

  if (!updateId) {
    errors.push('update_id manquant ou invalide');
  }

  if (!userId) {
    errors.push('from.id (user_id) manquant ou invalide');
  }

  if (errors.length > 0) {
    throw new Error(`Validation échouée: ${errors.join(', ')}`);
  }
}

// Exécution de la validation
validateRequiredFields(update.update_id, from.id);

// ============================================================================
// FONCTIONS UTILITAIRES
// ============================================================================

/**
 * Nettoie une chaîne pour utilisation SQL Server
 * - Échappe les apostrophes simples
 * - Supprime les caractères de contrôle dangereux
 * - Limite la longueur si spécifié
 * 
 * @param {string|null} str - Chaîne à nettoyer
 * @param {number} maxLength - Longueur maximale (optionnel)
 * @returns {string|null} - Chaîne nettoyée ou null
 */
function sanitizeString(str, maxLength = null) {
  if (str === null || str === undefined) {
    return null;
  }

  let cleaned = String(str)
    .replace(/'/g, "''")
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '');

  if (maxLength && cleaned.length > maxLength) {
    cleaned = cleaned.substring(0, maxLength);
  }

  return cleaned;
}

/**
 * Convertit un timestamp UNIX en format DATETIME SQL Server
 * Format de sortie : YYYY-MM-DD HH:MM:SS
 * 
 * @param {number|null} unixTimestamp - Timestamp UNIX (secondes)
 * @returns {string|null} - Date formatée ou null
 */
function convertUnixToSqlDatetime(unixTimestamp) {
  if (!unixTimestamp || typeof unixTimestamp !== 'number') {
    return null;
  }

  try {
    const date = new Date(unixTimestamp * 1000);

    // Vérification de validité de la date
    if (isNaN(date.getTime())) {
      return null;
    }

    return date.toISOString().slice(0, 19).replace('T', ' ');
  } catch (error) {
    return null;
  }
}

/**
 * Détecte la commande Telegram si présente
 * Analyse les entities pour trouver bot_command
 * 
 * @param {Array} entities - Tableau des entities Telegram
 * @param {string} messageText - Texte du message
 * @returns {string|null} - Nom de la commande ou null
 */
function detectCommand(entities, messageText) {
  if (!entities || entities.length === 0) {
    return null;
  }

  const commandEntity = entities.find(e => e.type === 'bot_command');

  if (commandEntity && messageText) {
    // Extraction du nom de la commande depuis le texte
    const commandText = messageText.substring(
      commandEntity.offset,
      commandEntity.offset + commandEntity.length
    );
    return sanitizeString(commandText, 100);
  }

  return commandEntity ? commandEntity.type : null;
}

/**
 * Convertit un booléen en BIT SQL Server (0 ou 1)
 * 
 * @param {boolean|null} value - Valeur booléenne
 * @returns {number} - 0 ou 1
 */
function booleanToBit(value) {
  return value === true ? 1 : 0;
}

// ============================================================================
// NORMALISATION DES DONNÉES
// ============================================================================

const normalizedData = {
  // Identifiants principaux
  update_id: update.update_id,
  message_id: message.message_id || null,

  // Informations utilisateur
  user_id: from.id,
  is_bot: booleanToBit(from.is_bot),
  first_name: sanitizeString(from.first_name, 255),
  last_name: sanitizeString(from.last_name, 255),
  username: sanitizeString(from.username, 255),
  language_code: sanitizeString(from.language_code, 10),

  // Informations chat
  chat_id: chat.id || from.id,
  chat_type: sanitizeString(chat.type || 'private', 50),
  chat_title: sanitizeString(chat.title, 255),

  // Contenu du message
  message_text: sanitizeString(message.text, 4000),
  command: detectCommand(entities, message.text),

  // Timestamps
  telegram_datetime: convertUnixToSqlDatetime(message.date),

  // Métadonnées de traitement
  processed_at: new Date().toISOString().slice(0, 19).replace('T', ' '),
  raw_update_id: update.update_id
};

// ============================================================================
// RETOUR DES DONNÉES NORMALISÉES
// ============================================================================

return {
  json: normalizedData
};

