// Normalisation des données Telegram
const update = $input.item.json;

const telegram_timestamp = update.message?.date || '';
const telegram_datetime = telegram_timestamp ? new Date(telegram_timestamp * 1000).toISOString() : '';
const traitement_datetime = new Date().toISOString();

return {
  json: {
    update_id: update.update_id || '',
    message_id: update.message?.message_id || '',
    user_id: update.message?.from?.id || '',
    is_bot: update.message?.from?.is_bot || '',
    first_name: update.message?.from?.first_name || '',
    last_name: update.message?.from?.last_name || '',
    language_code: update.message?.from?.language_code || '',
    chat_id: update.message?.chat?.id || '',
    chat_type: update.message?.chat?.type || '',
    message_text: update.message?.text || '',
    command: update.message?.entities?.[0]?.type || '',
    telegram_datetime,
    traitement_datetime
  }
};

// Génère une ligne CSV propre (sans headers)
const data = $input.item.json;

const escapeCsv = (value) => {
  if (value === null || value === undefined) return '';
  const str = String(value);
  if (str.includes(',') || str.includes('"') || str.includes('\n') || str.includes('\r')) {
    return '"' + str.replace(/"/g, '""') + '"';
  }
  return str;
};

const csvLine = [
  escapeCsv(data.update_id),
  escapeCsv(data.message_id),
  escapeCsv(data.user_id),
  escapeCsv(data.is_bot),
  escapeCsv(data.first_name),
  escapeCsv(data.last_name),
  escapeCsv(data.language_code),
  escapeCsv(data.chat_id),
  escapeCsv(data.chat_type),
  escapeCsv(data.message_text),
  escapeCsv(data.command),
  escapeCsv(data.telegram_datetime),
  escapeCsv(data.traitement_datetime)
].join(',') + '\n';

// Convertir en binaire pour le noeud Write Binary File
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(csvLine, 'utf8'),
  'line.csv',
  'text/csv'
);

return {
  json: { 
    csvLine: csvLine.trim(),
    ...data
  },
  binary: {
    data: binaryData
  }
};
